#include<bits/stdc++.h>
using namespace std;
int c[100010];
int fa[200010];
int s1[1000010],s2[1000010];
char s[1000010];
vector<int> v[200010];
long long ans[1000010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
map<char,int> id;
int main()
{
    int k;
    scanf("%d",&k);
    int tot=0;
    id['0']=k+1;
    v[k+1].push_back(0);
    v[k+1].push_back(++tot);
    id['1']=k+2;
    v[k+2].push_back(0);
    v[k+2].push_back(++tot);
    for(int i=1;i<=k;i++)
    {
        scanf("%d",&c[i]);
        id[i+'a'-1]=i;
        v[i].push_back(0);
        for(int j=1;j<=c[i];j++)
        {
            v[i].push_back(++tot);
        }
    }
    int n=0,m=0;
    scanf("%s",s+1);
    int len=strlen(s+1);
    for(int i=1;i<=len;i++)
    {
        if(s[i]=='0'||s[i]=='1')
        {
            s1[++n]=v[id[s[i]]][1];
        }
        else
        {
            for(int j=1;j<=c[id[s[i]]];j++)
            {
                s1[++n]=v[id[s[i]]][j];
            }
        }
    }
    scanf("%s",s+1);
    len=strlen(s+1);
    for(int i=1;i<=len;i++)
    {
        if(s[i]=='0'||s[i]=='1')
        {
            s2[++m]=v[id[s[i]]][1];
        }
        else
        {
            for(int j=1;j<=c[id[s[i]]];j++)
            {
                s2[++m]=v[id[s[i]]][j];
            }
        }
    }
    if(n!=m)
    {
        printf("0");
        return 0;
    }
    for(int i=1;i<=tot;i++)
    {
        fa[i]=i;
    }
    for(int i=1;i<=n;i++)
    {
        merge(s1[i],s2[i]);
    }
    if(find(1)==find(2))
    {
        printf("0");
        return 0;
    }
    long long cnt=0;
    for(int i=1;i<=tot;i++)
    {
        if(find(i)!=find(1)&&find(i)!=find(2)&&find(i)==i)
        {
            cnt++;
        }
    }
    ans[1]=1;
    len=1;
    for(long long i=1;i<=cnt;i++)
    {
        for(int j=1;j<=len;j++)
        {
            ans[j]*=2;
        }
        for(int j=1;j<=len;j++)
        {
            ans[j+1]+=ans[j]/10;
            ans[j]%=10;
        }
        while(ans[len+1])
        {
            len++;
        }
    }
    for(int i=len;i>=1;i--)
    {
        printf("%lld",ans[i]);
    }
    return 0;
}
